void		JNPGraphicsSetDSpContextAttributes	(DSpContextAttributes *	attributes,												short					screenWidth,												short					screenHeight,												short					screenDepth);//*************************************************************************************//  Graphics X functions//************************************************************************************OSStatus InstallGraphics (short screenWidth, short screenHeight, short screenDepth){	DSpContextAttributes attributes;	JNPGraphicsSetDSpContextAttributes(&attributes, screenWidth, screenHeight, screenDepth);	gJNPGraphicsXError = DSpStartup();	ReturnJNPGraphicsXError;	gJNPGraphicsXError = DSpFindBestContext(&attributes, &gJNPGraphicsContext);	ReturnJNPGraphicsXError;	gJNPGraphicsXError = DSpContext_Reserve(gJNPGraphicsContext, &attributes);	ReturnJNPGraphicsXError;	return noErr;}OSStatus UninstallGraphics (void){	gJNPGraphicsXError = DSpContext_Release(gJNPGraphicsContext);	ReturnJNPGraphicsXError;	gJNPGraphicsXError = DSpShutdown();	ReturnJNPGraphicsXError;	return noErr;}OSStatus FadeInGraphics (void){	if(gJNPGraphicsIsFaded == true)	{		gJNPGraphicsXError = DSpContext_FadeGammaIn(NULL, NULL);		ReturnJNPGraphicsXError;		gJNPGraphicsIsFaded = false;	}	return noErr;}OSStatus FadeOutGraphics (void){	if(gJNPGraphicsIsFaded == false)	{		gJNPGraphicsXError = DSpContext_FadeGammaOut(NULL, NULL);		ReturnJNPGraphicsXError;		gJNPGraphicsIsFaded = true;	}	return noErr;}OSStatus FadeInWindow (WindowRef myWindow){	return FadeInGraphics();}OSStatus FadeOutWindow (WindowRef myWindow){	return FadeOutGraphics();}OSStatus TurnFullScreenOn (WindowRef myWindow){	if(gJNPGraphicsIsFullScreen == false)	{		CGrafPtr oldCPort;		gJNPGraphicsXError = GetGWorld(&oldCPort);		ReturnJNPGraphicsXError		gJNPGraphicsXError = DSpContext_SetState(gJNPGraphicsContext, kDSpContextState_Active);		ReturnJNPGraphicsXError;		gJNPGraphicsXError = DSpContext_SetState(gJNPGraphicsContext, kDSpContextState_Paused);		ReturnJNPGraphicsXError;		gJNPGraphicsXError = SetGWorld(oldCPort);		ReturnJNPGraphicsXError;		HideMenuBar();		MoveWindow(myWindow, 0, 0, true);		ShowWindow(myWindow);		SelectWindow(myWindow);		gJNPGraphicsIsFullScreen = true;	}	return noErr;}OSStatus TurnFullScreenOff (WindowRef myWindow){	if(gJNPGraphicsIsFullScreen == true)	{		gJNPGraphicsXError = DSpContext_SetState(gJNPGraphicsContext, kDSpContextState_Inactive);		ReturnJNPGraphicsXError;		ShowMenuBar();		ShowWindow(myWindow);		SelectWindow(myWindow);		gJNPGraphicsIsFullScreen = false;	}	return noErr;}OSStatus ToggleFullScreen (WindowRef myWindow){	gJNPGraphicsXError = FadeOutGraphics();	ReturnJNPGraphicsXError;	if(gJNPGraphicsIsFullScreen == true)		gJNPGraphicsXError = TurnFullScreenOff(myWindow);	else		gJNPGraphicsXError = TurnFullScreenOn(myWindow);	ReturnJNPGraphicsXError;	gJNPGraphicsXError = FadeInGraphics();	ReturnJNPGraphicsXError;	return noErr;}Boolean IsFullScreenOn (void){	return gJNPGraphicsIsFullScreen;}//*************************************************************************************//  internal functions//*************************************************************************************void JNPGraphicsSetDSpContextAttributes (DSpContextAttributes * attributes, short screenWidth, short screenHeight, short screenDepth){	attributes->frequency					= 0;	attributes->displayWidth				= screenWidth;	attributes->displayHeight				= screenHeight;	attributes->reserved1					= 0;	attributes->reserved2					= 0;	attributes->colorNeeds					= kDSpColorNeeds_Require;	attributes->colorTable					= NULL;	attributes->contextOptions				= 0;	if(screenDepth <= 1)	{		attributes->backBufferDepthMask		= kDSpDepthMask_1;		attributes->displayDepthMask		= kDSpDepthMask_1;	}	else if(screenDepth <= 2)	{		attributes->backBufferDepthMask		= kDSpDepthMask_2;		attributes->displayDepthMask		= kDSpDepthMask_2;	}	else if(screenDepth <= 4)	{		attributes->backBufferDepthMask		= kDSpDepthMask_4;		attributes->displayDepthMask		= kDSpDepthMask_4;	}	else if(screenDepth <= 8)	{		attributes->backBufferDepthMask		= kDSpDepthMask_8;		attributes->displayDepthMask		= kDSpDepthMask_8;	}	else if(screenDepth <= 16)	{		attributes->backBufferDepthMask		= kDSpDepthMask_16;		attributes->displayDepthMask		= kDSpDepthMask_16;	}	else if(screenDepth <= 32)	{		attributes->backBufferDepthMask		= kDSpDepthMask_32;		attributes->displayDepthMask		= kDSpDepthMask_32;	}	else	{		attributes->backBufferDepthMask		= kDSpDepthMask_All;		attributes->displayDepthMask		= kDSpDepthMask_All;	}	attributes->backBufferBestDepth			= screenDepth;	attributes->displayBestDepth			= screenDepth;	attributes->pageCount					= 1;	attributes->filler[0]					= 0;	attributes->filler[1]					= 0;	attributes->filler[2]					= 0;	attributes->gameMustConfirmSwitch		= 0;	attributes->reserved3[0]				= 0;	attributes->reserved3[1]				= 0;	attributes->reserved3[2]				= 0;	attributes->reserved3[3]				= 0;}